$\begin{align}
&\phantom{=}4500\,\dfrac{\text{bacteria}}{\text{centimeter}^2}
\\\\
&=4500\,\dfrac{\text{bacteria}}{\text{centimeter}^2}\cdot \left(\blueD{\dfrac{1\,\text{centimeter}}{10\,\text{millimeter}}}\right)^2
\\\\
&=4500\,\dfrac{\text{bacteria}}{\cancel{\text{centimeter}^2}}\cdot \blueD{\dfrac{1\,\cancel{\text{centimeter}^2}}{100\,\text{millimeter}^2}}
\\\\
&=\dfrac{4500}{100}\,\dfrac{\text{bacteria}}{\text{millimeter}^2}
\\\\
&=45\,\dfrac{\text{bacteria}}{\text{millimeter}^2}
\end{align}$

